return ['domain'=>NULL,'plural-forms'=>'nplurals=3; plural=(n%10==1 && n%100!=11 ? 0 : n%10>=2 && n%10<=4 && (n%100<12 || n%100>14) ? 1 : 2);','language'=>'sr_RS','pot-creation-date'=>'2026-03-06 15:40+0100','po-revision-date'=>'2026-03-06 15:40+0100','translation-revision-date'=>'2026-03-06 15:40+0100','project-id-version'=>'Serbian Transliteration','x-generator'=>'Poedit 3.8','messages'=>['Block Editor: Script selector' . "\4" . 'Latin'=>'Латиница','Block Editor: Script selector' . "\4" . 'Cyrillic'=>'Ћирилица','Block Editor: Script selector' . "\4" . 'Choose your display type:'=>'Изаберите врсту приказа:','Block Editor: Script selector' . "\4" . 'Script Selector'=>'Избор писма','Block Editor: Script selector' . "\4" . 'Inline'=>'У реду','Block Editor: Script selector' . "\4" . 'Select'=>'Изабери','Block Editor: Script selector' . "\4" . 'List'=>'Листа','Block Editor: Script selector' . "\4" . 'List items'=>'Ставке листе','Block Editor: Script selector' . "\4" . 'Separator:'=>'Раздвајач:','Block Editor: Script selector' . "\4" . 'Cyrillic caption:'=>'Ћирилични наслов:','Block Editor: Script selector' . "\4" . 'Latin Caption:'=>'Латинични наслов:','undefined'=>'недефинисано','Freelance Jobs - Find or post freelance jobs'=>'Фриленс послови - Пронађи или објави фриленс послове','Contra Team - A complete hosting solution in one place'=>'Contra Team - Комплетно решење за хостинг на једном месту','Transliteration'=>'Пресловљавање','Latin'=>'Латиница','Cyrillic'=>'Ћирилица','Help'=>'Помоћ','To insert language script selector just add a relative link after the link\'s keyword, example :'=>'Да бисте уметнули бирач скрипте језика, додајте релативну везу после кључне речи везе, на пример:','You can also use'=>'Такође можете користити','for change to Latin or use'=>'за промену у латиницу или','for change to Cyrillic'=>'за промену на ћирилицу','Add to Menu'=>'Додај у изборник','The name of this navigation is written by always putting the Latin name first, then the Cyrillic one second, separated by the sign %s'=>'Назив ове навигације пише се тако што се на прво место увек ставља латинични назив, а затим ћирилични на друго место, одвојено знаком %s','Example: Latinica | Ћирилица'=>'Пример: Latinica | Ћирилица','Note that the white space around them will be cleared.'=>'Имајте на уму да ће се размак око њих очистити.','You have been using <b> %1$s </b> plugin for a while. We hope you liked it!'=>'Већ неко време користите <b>%1$s</b>. Надамо се да вам се допада!','Please give us a quick rating, it works as a boost for us to keep working on the plugin!'=>'Молимо вас за једну брзу оцену, то нам делује као подстицај да наставимо да радимо на додатку!','Rate Now!'=>'Оцените нас!','I\'ve already done that!'=>'То сам већ учинио!','Hey there! It\'s been a while since you\'ve been using the <b> %1$s </b> plugin'=>'Хеј тамо! Прошло је доста времена од када си инсталирао додатак за <b> %1$s </b>','I\'m glad to hear you\'re enjoying the plugin. I\'ve put a lot of time and effort into ensuring that your website runs smoothly. If you\'re feeling generous, how about %s for my hard work? 😊'=>'Тако ми је драго да ти се допада додатак. Уложио сам много времена и љубави како бих осигурао да твоја веб локација ради несметано. Ако се осећаш великодушно, шта кажеш %s за труд? 😊','treating me to a coffee'=>'да ме почастиш једном кафом','Or simply %s forever.'=>'Или једноставно %s заувек.','hide this message'=>'сакриј ову поруку','Hey there! It\'s been a while since you\'ve been using the <b>%1$s</b> plugin'=>'Поздрав! Већ неко време користиш додатак за <b>%1$s</b>','I\'m really happy to see this plugin being useful for your website. If you ever feel like giving back, here\'s one way to do it.'=>'Баш ми је драго што је овај додатак користан за твој сајт. Ако икада пожелиш да узвратиш подршком, ево једног начина да то учиниш.','Bank account (Banca Intesa a.d. Beograd):'=>'Број рачуна (Банка Интеса а.д. Београд):','Every little bit helps, and I truly appreciate it! ❤️'=>'Свака помоћ значи, и искрено сам захвалан! ❤️','Find Work or %1$s in Serbia, Bosnia, Croatia, and Beyond!'=>'Пронађи посао или %1$s у Србији, Босни, Хрватској и шире!','Visit %2$s to connect with skilled professionals across the region. Whether you need a project completed or are looking for work, our platform is your gateway to successful collaboration.'=>'Посетите %2$s да бисте се повезали са вештим професионалцима широм региона. Било да вам је потребан завршен пројекат или тражите посао, наша платформа је ваша капија за успешну сарадњу.','Hire Top Freelancers'=>'aнгажуј врхунске фриленсере','Freelance Jobs'=>'Фриленс послови','Join us today!'=>'Придружи нам се данас!','This plugin uses cookies and should be listed in your Privacy Policy page to prevent privacy issues.'=>'Овај додатак користи колачиће и требао би бити наведен на вашој страници политике приватности како би се спречили проблеми са приватношћу.','Suggested text:'=>'Предложени текст:','This website uses the %1$s plugin to transliterate content.'=>'Ова веб локација користи додатак %1$s за пресловљавање садржаја.','This is a simple and easy add-on with which this website translates content from Cyrillic to Latin and vice versa. This transliteration plugin also supports special shortcodes and functions that use cookies to specify the language script.'=>'Ово је једноставан и лаган додатак са којим ова веб локација преводи садржај са ћирилице на латиницу и обрнуто. Овај додатак за преслољавање (транслитерацију) такође подржава посебне кратке кодове и функције које користе колачиће за одређивање језичке скрипте.','These cookies do not affect your privacy because they are not intended for tracking and analytics. These cookies can have only two values: "%1$s" or "%2$s".'=>'Ови колачићи не утичу на вашу приватност јер нису намењени за праћење и аналитику. Ови колачићи могу имати само две вредности: "%1$s" или "%2$s".','Important upgrade notice for the version %s:'=>'Важно обавештење о надоградњи за верзију %s:','NOTE: Before doing the update, it would be a good idea to backup your WordPress installations and settings.'=>'НАПОМЕНА: Пре него што извршите ажурирање, било би добро да направите резервне копије ваших WordPress инсталација и подешавања.','The %1$s cannot run on PHP versions older than PHP %2$s. Please contact your host and ask them to upgrade.'=>'%1$s не може да се покреће на PHP верзијама старијим од PHP%2$s. Молимо контактирајте свог сервер администратора и замолите га да изврши надоградњу.','Transliteration plugin requires attention:'=>'Додатак за пресловљавање захтева пажњу:','Your plugin works under Only WooCoomerce mode and you need to %s because WooCommerce is no longer active.'=>'Ваш додатак ради у WooCoomerce режиму и требате %s јер WooCoomerce више није активан.','update your settings'=>'ажурирати своја подешавања','Transliteration plugin requires a Multibyte String PHP extension (mbstring).'=>'Додатак за пресловљавање захтева "Multibyte String PHP " екстензију (mbstring).','Without %s you will not be able to use this plugin.'=>'Без %s нећете моћи да користите овај додатак.','Multibyte String Installation'=>'Multibyte String инсталација','this PHP extension'=>'ове PHP екстензије','The %1$s cannot run on WordPress versions older than %2$s. Please update your WordPress installation.'=>'%1$s не може да се покреће за верзије WordPress-а старије од %2$s. Ажурирајте своју WordPress инсталацију.','Global Settings'=>'Глобална подешавања','My site is'=>'Мој сајт је','Transliteration Mode'=>'Режим пресловљавања','First visit mode'=>'Режим прве посете','Language scheme'=>'Језичка шема','Plugin Mode'=>'Начин рада додатка','Force transliteration permalinks to latin'=>'Присилите пресловљавање трајних веза (пермалинкова) на латиницу','Filters'=>'Филтери','Transliteration Filters'=>'Филтери за пресловљавање','Exclude Latin words that you do not want to be transliterated to the Cyrillic.'=>'Искључите латиничне речи за које не желите да се преслове у ћирилицу.','Exclude Cyrillic words that you do not want to be transliterated to the Latin.'=>'Изузмите ћириличне речи за које не желите да се пресловите у латиницу.','Special Settings'=>'Специјална подешавања','Enable cache support'=>'Омогућите подршку за кеширање','Force widget transliteration'=>'Присилно пресловљавање виџета','Force e-mail transliteration'=>'Присилно пресловљавање е-маил порука','Force transliteration for WordPress REST API'=>'Форсирај пресловљавање за WordPress REST API позиве','Force transliteration for AJAX calls'=>'Форсирај пресловљавање за AJAX позиве','EXPERIMENTAL'=>'ЕКСПЕРИМЕНТАЛНО','WP Admin'=>'Административни део','WP-Admin transliteration'=>'Пресловљавање администрације','Allow Cyrillic Usernames'=>'Дозволи ћирилична корисничка имена','Allow Admin Tools'=>'Дозволи админ алатке','Media Settings'=>'Подешавање садржаја и фајлова','Transliterate filenames to latin'=>'Транскрипција медија фајлова на латиницу','Filename delimiter'=>'Раздвајање речи у имену фајла','WordPress Search'=>'WordPress претрага','Enable search transliteration'=>'Активирај пресловљавање претраге','Fix Diacritics'=>'Поправите дијакритику','Search Mode'=>'Врста претраге','SEO Settings'=>'СЕО (Search engine optimization) подешавања','Parameter URL selector'=>'Бирач УРЛ-а параметра','RSS transliteration'=>'Пресловљавање "RSS" документа','Exclusion'=>'Искључење','Language: %s'=>'Језик: %s','Misc.'=>'Разно','Enable body class'=>'Омогући "body" класу','Theme Support'=>'Подршка за теме','Support the Project'=>'Подржите пројекат','Contributors & Developers'=>'Сарадници и програмери','This setting determines the mode of operation for the Transliteration plugin.'=>'Ово подешавање одређује начин рада додатка за пресловљавање.','Carefully choose the option that is best for your site and the plugin will automatically set everything you need for optimal performance.'=>'Пажљиво изаберите опцију која је најбоља за вашу страницу и додатак ће аутоматски поставити све што је потребно за оптималне перформансе.','This section contains filters for exclusions, allowing you to specify content that should be excluded from transliteration, and also includes a filter to disable certain WordPress filters related to transliteration.'=>'Овај одељак садржи филтере за изузимања, који вам омогућавају да одредите садржај који треба да буде искључен из транслитерације, а такође укључује филтер за онемогућавање одређених WordPress филтера који се односе на транслитерацију.','These are special settings that can enhance transliteration and are used only if you need them.'=>'Ово су посебна подешавања која могу побољшати транслитерацију и користе се само ако су вам неопходна.','These settings apply to the administrative part.'=>'Ова подешавања се односе на административни део.','Upload, view and control media and files.'=>'Отпремање, прегледање и контрола медија и датотека.','Our plugin also has special SEO options that are very important for your project.'=>'Наш додатак такође има посебне СЕО опције које су веома важне за ваш пројекат.','Within this configuration section, you have the opportunity to customize your experience by selecting the particular languages for which you wish to turn off the transliteration function. This feature is designed to give you greater control and adaptability over how the system handles transliteration, allowing you to disable it for specific languages based on your individual needs or preferences.'=>'У оквиру овог дела за конфигурацију, имате прилику да прилагодите своје искуство тако што ћете изабрати одређене језике за које желите да искључите функцију транслитерације. Ова функција је дизајнирана да вам пружи већу контролу и прилагодљивост у вези са начином на који систем обрађује транслитерацију, омогућавајући вам да је искључите за специфичне језике на основу ваших индивидуалних потреба или преференци.','Various interesting settings that can be used in the development of your project.'=>'Разне занимљиве поставке које се могу користити у развоју вашег пројекта.','This setting determines the search mode within the WordPress core depending on the type of language located in the database.'=>'Ово подешавање одређује режим претраживања у језгру WordPress-а у зависности од врсте језика који се налази у бази података.','The search type setting is mostly experimental and you need to test each variant so you can get the best result you need.'=>'Подешавање типа претраге је углавном експериментално и треба да тестирате сваку варијанту како бисте постигли најбољи резултат који вам је потребан.','Arabic'=>'Арапски','Armenian'=>'Арменијски','Define whether your primary alphabet on the site is Latin or Cyrillic. If the primary alphabet is Cyrillic then choose Cyrillic. If it is Latin, then choose Latin. This option is crucial for the plugin to work properly.'=>'Дефинишите да ли је ваше примарно писмо на сајту латиница или ћирилица. Ако је примарно писмо ћирилица онда одаберите ћирилицу. Ако је латиница, онда одаберите латиницу. Ова опција је кључна за исправан рад плугина.','Define whether your primary alphabet on the site.'=>'Одредите да ли је ваш примарни алфабет на сајту.','Transliteration disabled'=>'Угаси пресловљавање','Cyrillic to Latin'=>'Ћирилица у латиницу','Latin to Cyrillic'=>'Латиница у ћирилицу','Arabic to Latin'=>'Арапски у латиницу','Latin to Arabic'=>'Латиница у арапски','Armenian to Latin'=>'Арменијски у латиницу','Latin to Armenian'=>'Латиница у арменијски','This option determines the global transliteration of your web site. If you do not want to transliterate the entire website and use this plugin for other purposes, disable this option. This option does not affect to the functionality of short codes and tags.'=>'Ова опција одређује глобално пресловљавање ваше веб странице. Ако не желите да пресловите целу веб локацију и користите овај додатак у друге сврхе, онемогућите ову опцију. Ова опција не утиче на функционалност кратких кодова и ознака.','This option determines the type of language script that the visitors sees when they first time come to your site.'=>'Ова опција одређује врсту скрипте на језику коју посетиоци виде када први пут дођу на вашу страницу.','Automatical'=>'Аутоматски','This option defines the language script. Automatic script detection is the best way but if you are using a WordPress installation in a language that does not match the scripts supported by this plugin, then choose on which script you want the transliteration to be performed.'=>'Ова опција дефинише језичко писмо. Аутоматско откривање скрипти је најбољи начин, али ако користите WordPress инсталацију на језику који се не подудара са скриптама које подржава овај додатак, онда одаберите на којој скрипти желите да се изврши транслитерација.','This option configures the operating mode of the entire plugin and affects all aspects of the site related to transliteration. Each mode has its own set of filters, which are activated based on your specific needs. It\'s important to take the time to review and customize these settings according to your preferences.'=>'Ова опција конфигурише оперативни режим целог додатка и утиче на све аспекте сајта који су везани за транслитерацију. Сваки режим има свој скуп филтера, који се активирају на основу ваших специфичних потреба. Важно је да одвојите време да прегледате и прилагодите ова подешавања према вашим преференцијама.','Forced transliteration can sometimes cause problems if Latin is translated into Cyrillic in pages and posts. To this combination must be approached experimentally.'=>'Принудно пресловљавање понекад може да створи проблеме ако се латиница на страницама и у порукама преведе на ћирилицу. Овој комбинацији се мора приступити експериментално.','Exclude filters you don\'t need (optional)'=>'Уклоните филтере који вам нису потребни (опционално)','Select the transliteration filters you want to exclude.'=>'Изаберите филтере за пресловљавање које желите да уклоните (искључите).','The filters you select here will not be transliterated (these filters do not work on forced transliteration).'=>'Овде изабрани филтри неће бити пресловљени (ови филтери не раде на присилном пресловљавању).','TIPS & TRICKS:'=>'САВЕТИ И ТРИКОВИ:','You can find details about some of the listed filters in this article:'=>'Детаље о неким од наведених филтера можете пронаћи у овом чланку:','Since you are already a WooCommerce user, you also can see the following documentation: %s'=>'Пошто сте већ корисник WooCommerce-а, можете видети и следећу документацију: %s','Separate words, phrases, names and expressions with the sign %s or put it in a new row. HTML is not allowed.'=>'Одвојите речи, фразе, имена и изразе знаком %s или их ставите у нови ред. HTML није дозвољен.','Yes'=>'Да','No'=>'Не','If you have a problem caching your pages, our plugin solves this problem by clearing the cache when changing the language script.'=>'Ако имате проблем са кеширањем страница, наша додатна компонента решава овај проблем брисањем кеш меморије приликом промене скрипте језика.','This option forces the widget to transliterate. There may be some unusual behaviour in the rare cases.'=>'Ова опција приморава виџете да се преслове. У ретким случајевима може бити необичног понашања.','Enable this feature if you want to force transliteration of email content.'=>'Омогућите ову функцију ако желите да форсирате транслитерацију садржаја е-поште.','Enable this feature if you want to force transliteration of WordPress REST API calls. The WordPress REST API is also used in many AJAX calls, WooCommerce, and page builders. It is recommended to be enabled by default.'=>'Омогућите ову функцију ако желите да принудно извршите транслитерацију позива WordPress REST API-ја. WordPress REST API се такође користи у многим AJAX позивима, WooCommerce-у и градитељима страница. Препоручује се да буде омогућено по подразумеваном.','Enable this feature if you want to force transliteration of AJAX calls. If you want to avoid transliteration of specific individual AJAX calls, you must add a new POST or GET parameter to your AJAX call: %s'=>'Омогућите ову функцију ако желите да приморате пресловљавање AJAX позива. Ако желите да избегнете пресловљавање одређених појединачних AJAX позива, морате додати нови POST или GET параметар %s на ваш AJAX позив.','Enable if you want the WP-Admin area to be transliterated.'=>'Омогућите ако желите да се WP-Admin област пресловљава.','Allows to create users with usernames containing Cyrillic characters.'=>'Омогућава стварање корисника са корисничким именима која садрже ћириличне знакове.','This feature enables you to easily transliterate titles and content directly within the WordPress editor. This functionality is available for various content types, including categories, pages, posts, and custom post types, ensuring a seamless experience when managing multilingual content on your site. With just a few clicks, you can switch between scripts, making your content accessible to a broader audience.'=>'Ова функција вам омогућава да лако пресловљавате наслове и садржај директно унутар WordPress едитора. Ова функционалност је доступна за различите типове садржаја, укључујући категорије, странице, постове и прилагођене типове постова, обезбеђујући беспрекорно искуство при управљању вишејезичним садржајем на вашем сајту. Уз само неколико кликова, можете мењати писма, чинећи ваш садржај приступачним широј публици.','Enable if you want to force cyrillic permalinks to latin.'=>'Омогућите ако желите да форсирате ћирилицу на латиницу.','Enable if you want to convert cyrillic filenames to latin.'=>'Омогућите ако желите да претворите ћириличне фајлове у латиницу.','hyphen (default)'=>'цртица (подразумевано)','underscore'=>'доња црта','dot'=>'тачка','tilde'=>'тилда','vartical bar'=>'вертикална трака','asterisk'=>'звездица','Filename delimiter, example:'=>'Одвајање имена фајла. На пример:','my-upload-file.jpg'=>'naziv-moga-fajla.jpg','Approve if you want transliteration for the search field.'=>'Одобрите ако желите пресловљавање поља за претрагу.','Try to fix the diacritics in the search field.'=>'Покушајте да поправите дијакритике у пољу за претрагу.','Automatical (recommended)'=>'Аутоматски (препоручено)','Based on the plugin mode'=>'Базирано на режиму пресловљавања','The search has two working modes. Choose the one that works best with your search.'=>'Претрага има два начина рада. Изаберите ону која најбоље одговара вашој претрази.','(safe)'=>'(сигурно)','(standard)'=>'(стандардно)','(optional)'=>'(опционо)','This option dictates which URL parameter will be used to change the language.'=>'Ова опција диктира који ће се параметар УРЛ-а користити за промену језика.','This option transliterate the RSS feed.'=>'Ова опција пресловљава "RSS" документе.','Transliterate'=>'Преслови','Omit the transliteration'=>'Изостави транслитерацију','This option adds CSS classes to your body HTML tag. These CSS classes vary depending on the language script.'=>'Ова опција додаје CSS класе у вашу HTML ознаку тела. Ове класе CSS-а се разликују у зависности од језичке скрипте.','Enable Theme Support'=>'Омогућите подршку за теме','Disable Theme Support'=>'Онемогућите подршку за теме','If you don\'t require transliteration support for your theme, you can disable it for your current theme here.'=>'Ако вам није потребна подршка за транслитерацију за своју тему, можете је онемогућити за своју тренутну тему овде.','This mode has no filters.'=>'Овај режим нема филтере.','Transliterator is free to use and actively maintained. Ongoing updates, performance improvements, and new features require continuous time and resources.'=>'Транслитератор је бесплатан за коришћење и активно се одржава. Континуирана ажурирања, побољшања перформанси и нове функционалности захтевају време и ресурсе.','If the plugin adds value to your work, you are welcome to support its further development with a voluntary contribution.'=>'Ако додатак доприноси вашем раду, можете подржати његов даљи развој добровољним прилогом.','Banca Intesa a.d. Beograd'=>'Банка Интеса а.д. Београд','Thank you for your support.'=>'Хвала вам на подршци.','If you want to support our work and effort, if you have new ideas or want to improve the existing code, %s.'=>'Ако желите да подржите наш рад и труд, ако имате нове идеје или желите да побољшате постојећи код, %s.','join our team'=>'придружите се нашем тиму','Settings saved.'=>'Подешавања су сачувана.','Settings'=>'Подешавања','Shortcodes'=>'Кратки кодови','PHP Functions'=>'PHP функције','5 stars?'=>'5 звезда?','Transliteration Settings'=>'Транслитерација - Подешавање','To Latin'=>'На латиницу','To Cyrillic'=>'На ћирилицу','Transliterate:'=>'Преслови:','Loading...'=>'Причекајте...','Please wait! Do not close the window or leave the page until this operation is completed!'=>'Сачекајте! Не затварајте прозор и не напуштајте страницу док се ова операција не заврши!','DONE!!!'=>'ГОТОВО!!!','PLEASE UPDATE PLUGIN SETTINGS'=>'МОЛИМО АЖУРИРАЈТЕ ПОСТАВКЕ ДОДАТКА','Carefully review the transliteration plugin settings and adjust how it fits your WordPress installation. It is important that every time you change the settings, you test the parts of the site that are affected by this plugin.'=>'Пажљиво прегледајте поставке додатка за пресловљавање и прилагодите како одговара вашој WordPress инсталацији. Важно је да сваки пут када промените поставке тестирате делове веб локације на које утиче овај додатак.','Tags'=>'Тагови','Transliteration Tool'=>'Алат за пресловљавање','Permalink Tool'=>'Алат за трајне везе','General Settings'=>'Глобална подешавања','Documentation'=>'Документација','Tools'=>'Алати','Debug'=>'Дебаговање','Credits'=>'Информације','Save Changes'=>'Сачувај промене','Available shortcodes'=>'Доступни кратки кодови','Available PHP Functions'=>'Доступне PHP функције','Available Tags'=>'Доступни тагови','Converter for transliterating Cyrillic into Latin and vice versa'=>'Конвертор за пресловљавање ћирилице у латиницу и обрнуто','Permalink Transliteration Tool'=>'Алат за пресловљавање трајних веза','Debug information'=>'Информације о отклањању грешака','WordPress Transliterator'=>'WordPress пресловљавање','Quick Access:'=>'Брз приступ:','Rate us'=>'Оцените нас','Current Settings:'=>'Тренутна подешавања:','Transliteration Mode:'=>'Режим пресловљавања:','Cache Support:'=>'Подршка за кеширање:','Media Transliteration:'=>'Пресловљавање медија:','Permalink Transliteration:'=>'Пресловљавање трајних веза:','Transliterator plugin options are not yet available. Please update plugin settings!'=>'Опције Transliterator додатка још увек нису доступне. Молимо вас да ажурирате подешавања додатка!','Support'=>'Подршка','This plugin is 100% free. If you want to buy us one coffee, beer or in general help the development of this plugin through a monetary donation, you can do it in the following ways:'=>'Овај додатак је 100% бесплатан. Ако желите да нам купите једну кафу, пиво или уопште да помогнете развој овог додатка кроз новчану донацију, то можете учинити на следеће начине:','From Serbia'=>'Из Србије','This is a light weight, simple and easy plugin with which you can transliterate your WordPress installation from Cyrillic to Latin and vice versa in a few clicks. This transliteration plugin also supports special shortcodes that you can use to partially transliterate parts of the content.'=>'Ово је једноставан и лаган додатак са којим ова веб локација преводи садржај са ћирилице на латиницу и обрнуто. Овај додатак за преслољавање (транслитерацију) такође подржава посебне кратке кодове и функције које користе колачиће за одређивање језичке скрипте.','Sponsors of this plugin:'=>'Спонзори овог додатка:','If you want to help develop this plugin and be one of the sponsors, please contact us at: %s'=>'Ако желите да помогнете у развоју овог додатка и будете један од спонзора, контактирајте нас на: %s','Special thanks to the contributors in the development of this plugin:'=>'Посебна захвалност сарадницима у развоју овог додатка:','Copyright'=>'Ауторско право','Copyright &copy; 2020 - %1$d %2$s by %3$s. All Right Reserved.'=>'Ауторско право &copy; 2020 - %1$d %2$s од %3$s. Сва права задржава.','Transliterator – WordPress Transliteration'=>'Пресловљавање - WordPress пресловљавање','This program is free software; you can redistribute it and/or modify it under the terms of the GNU General Public License as published by the Free Software Foundation; either version 2 of the License, or (at your option) any later version.'=>'Овај програм је бесплатан софтвер; можете га дистрибуирати и/или модификовати под условима ГНУ (General Public License ) коју је објавила Фондација за слободан софтвер; било верзију 2 лиценце, или (по вашој жељи) било коју новију верзију.','This program is distributed in the hope that it will be useful, but WITHOUT ANY WARRANTY; without even the implied warranty of MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.'=>'Овај програм се дистрибуира у нади да ће бити користан, али БЕЗ БИЛО КОЈЕ ГАРАНЦИЈЕ; чак ни под подразумеваном гаранцијом ЗА ПРОДАЈУ И СПОСОБНОСТИ ЗА ОДРЕЂЕНУ СВРХУ.','See the GNU General Public License for more details.'=>'Погледајте ГНУ (General Public License) за више детаља.','You should have received a copy of the GNU General Public License along with this program; if not, write to the Free Software Foundation, Inc., 51 Franklin Street, Fifth Floor, Boston, MA 02110-1301, USA.'=>'Требали сте да добијете копију ГНУ (General Public License ) заједно са овим плугином; ако нисте, обратите се Free Software Foundation, Inc., 51 Franklin Street, Fifth Floor, Boston, MA 02110-1301, USA.','Plugin ID'=>'Индентификација додатка','Plugin version'=>'Верзија додатка','WordPress version'=>'WordPress верзија','Last plugin update'=>'Последње ажурирање додатка','PHP version'=>'PHP верзија','PHP version ID'=>'Индентификатор PHP верзије','PHP architecture'=>'PHP архитектура','%d bit'=>'%d бита','WordPress debug'=>'WordPress отклањање грешака','On'=>'Укључено','Off'=>'Угашено','WordPress multisite'=>'WordPress мулти сајт','WooCommerce active'=>'WooCommerce је активан','WooCommerce version'=>'WooCommerce верзија','Site title'=>'Наслов сајта','Tagline'=>'Слоган','WordPress address (URL)'=>'WordPress адреса (URL)','Admin email'=>'Е-маил администратора','Encoding for pages and feeds'=>'Енкодирање за странице и храниоце (feeds)','Content-Type'=>'Тип садржаја','Site Language'=>'Језик сајта','Server time'=>'Време сервера','WordPress directory path'=>'Путања WordPress директоријума','Operting system'=>'Оперативни систем','User agent'=>'Кориснички агент','Plugin directory path'=>'Путања директоријума додатака','Plugin settings'=>'Начин рада додатка','These are available PHP functions that you can use in your themes and plugins.'=>'Ово су доступне функције које можете користити у својим темама и додацима.','Determines whether the site is already in Cyrillic.'=>'Утврђује да ли је веб локација већ на ћирилици.','This function provides information on whether the currently active language is excluded from transliteration.'=>'Ова функција пружа информације о томе да ли је тренутно активан језик искључен из транслитерације.','Transliteration of some text or content into the desired script.'=>'Пресловљавање одређеног текста или садржаја у жељену скрипту.','The <b><i>$type</i></b> parameter has two values: <code>cyr_to_lat</code> (Cyrillic to Latin) and <code>lat_to_cyr</code> (Latin to Cyrillic)'=>'Параметар <b><i>$type</i></b> има две вредности: <code>cyr_to_lat</code> (ћирилица у латиницу) and <code>lat_to_cyr</code> (латиница у ћирилицу)','Transliteration from Cyrillic to Latin.'=>'Пресловљавање са ћирилице на латиницу.','Transliteration from Latin to Cyrillic.'=>'Пресловљавање са латинице на ћирилицу.','Transliterates Cyrillic characters to Latin, converting them to their basic ASCII equivalents by removing diacritics.'=>'Пресловљава ћириличне карактере у латиницу, претварајући их у основне ASCII еквиваленте уклањањем дијакритика.','Get active script.'=>'Враћа активну скрипту.','This function displays a selector for the transliteration script.'=>'Ова функција приказује навигацију скрипте за транслитерацију.','Parameters'=>'Параметри','This attribute contains an associative set of parameters for this function:'=>'Овај атрибут садржи асоцијативни скуп параметара за ову функцију:','(string) The type of selector that will be displayed on the site. It can be: %1$s, %2$s, %3$s, %4$s, %5$s or %6$s. Default: %1$s'=>'(стринг) Тип селектора који ће бити приказан на сајту. Може бити: %1$s, %2$s, %3$s, %4$s, %5$s or %6$s. Подразумевано: "%1$s"','(bool) determines whether it will be displayed through an echo or as a string. Default: %s'=>'(bool) одређује да ли ће се приказивати кроз ехо или као низ. Подразумевано: %s','(string) Separator to be used when the selector type is %s. Default: %s'=>'(стринг) Сепаратор који се користи када је тип селектора %s. Подразумевано: %s','(string) Text for Cyrillic link. Default: %s'=>'(стринг) Текст за ћирилични линк. Подразумевано: %s','(string) Text for Latin link. Default: %s'=>'(стринг) Текст за латинични линк. Подразумевано: %s','This tool enables you to convert all existing Cyrillic permalinks in your database to Latin characters.'=>'Овај алат вам омогућава да конвертујете све постојеће линкове на ћирилици у вашој бази података у латинична слова.','Warning:'=>'Упозорење:','This option is dangerous and can create unexpected problems. Once you run this script, all permalinks in your database will be modified and this can affect on the SEO causing a 404 error.'=>'Ова опција је опасна и може створити неочекиване проблеме. Када покренете овај скрипт, сви линкови у вашој бази података биће модификовани, што може утицати на SEO и изазвати грешку 404.','Before proceeding, consult with your SEO specialist, as you will likely need to resubmit your sitemap and adjust other settings to update the permalinks in search engines.'=>'Пре него што наставите, консултујте се са вашим SEO стручњаком, јер ће вероватно бити потребно да поново пошаљете вашу мапу сајта и прилагодите друга подешавања како бисте ажурирали линкове у претраживачима.','For advanced users, this function can also be executed via WP-CLI using the command'=>'За напредне кориснике, ова функција се може извршити и преко WP-CLI коришћењем команде','Important: Make sure to %s before running this script.'=>'Важно: Уверите се да %s пре него што покренете овај скрипт.','back up your database'=>'направите резервну копију ваше базе података','This tool will affect on the following post types: %s'=>'Ова алатка ће утицати на следеће типове постова: %s','Let\'s do magic'=>'Направимо магију','Are you sure you want this?'=>'Да ли сте сигурни да желите ово?','Disclaimer'=>'Изјава о одрицању одговорности','While this tool is designed to operate safely, there is always a small risk of unpredictable issues.'=>'Иако је овај алат дизајниран да ради безбедно, увек постоји мали ризик од непредвидивих проблема.','Note: We do not guarantee that this tool will function correctly on your server. By using it, you assume all risks and responsibilities for any potential issues.'=>'Напомена: Не гарантујемо да ће овај алат исправно функционисати на вашем серверу. Коришћењем овог алата преузимате све ризике и одговорности за било какве потенцијалне проблеме.','Backup your database before using this tool.'=>'Направите резервну копију ваше базе података пре него што употребите овај алат.','These are available shortcodes that you can use in your content, visual editors, themes and plugins.'=>'Ово су доступни кратки кодови које можете да користите у свом садржају, визуелним уређивачима, темама и додацима.','Skip transliteration'=>'Избегни пресловљавање','Keep this original'=>'Сачувај ово оригинално','(optional) correct HTML code.'=>'(опционално) подржава ХТМЛ тагове.','Optional shortcode parameters'=>'Опционални параметри кратког кода','(optional) correct diacritics.'=>'(опционално) тачна дијакритика.','Add an image depending on the language script'=>'Додајте слику у зависности од писма','With this shortcode you can manipulate images and display images in Latin or Cyrillic depending on the setup.'=>'Овим кратким кодом можете да манипулишете сликама и приказујете слике на латиници или ћирилици, у зависности од подешавања.','Example'=>'Пример','Main shortcode parameters'=>'Главни параметри кратког кода','URL (src) as shown in the Latin language'=>'УРЛ (src) као што је приказано на латиничном језику','URL (src) as shown in the Cyrillic language'=>'УРЛ (src) како је приказано на ћирилици','(optional) URL (src) to the default image if Latin and Cyrillic are unavailable'=>'(опционално) УРЛ (src) на подразумевану слику ако латиница и ћирилица нису доступни','(optional) title (alt) description of the image for Cyrillic'=>'(необавезно) наслов (alt) опис слике за ћирилицу','(optional) caption description of the image for Cyrillic'=>'(необавезно) опис слике за ћирилицу','(optional) title (alt) description of the image for Latin'=>'(необавезно) наслов (алт) слике за латиницу','(optional) caption description of the image for Latin'=>'(необавезно) опис слике на латиници','(optional) title (alt) description of the image if Latin and Cyrillic are unavailable'=>'опционално) наслов (алт) слике ако латиница и ћирилица нису доступни','(optional) caption description of the imag if Latin and Cyrillic are unavailable'=>'(необавезно) опис описа слике ако латиница и ћирилица нису доступни','Shortcode return'=>'Кратки код враћа','HTML image corresponding to the parameters set in this shortcode.'=>'HTML слика која одговара параметрима постављеним у овом кратком коду.','Language script menu'=>'Изборник скрипте језика','This shortcode displays a selector for the transliteration script.'=>'Овај кратки код приказује навигацију скрипте за транслитерацију.','(string) The type of selector that will be displayed on the site. It can be: "%1$s", "%2$s", "%3$s" or "%4$s"'=>'(стринг) Тип селектора који ће бити приказан на сајту. Може бити: "%1$s", "%2$s", "%3$s" или "%4$s"','(string) Text for Cyrillic link. Default: Cyrillic'=>'(стринг) Текст за ћирилични линк. Подразумевано: Ћирилица','(string) Text for Latin link. Default: Latin'=>'(стринг) Текст за латинични линк. Подразумевано: Латиница','This shortcodes work independently of the plugin settings and can be used anywhere within WordPress pages, posts, taxonomies and widgets (if they support it).'=>'Ови кратки кодови раде независно од подешавања додатка и могу се користити било где у оквиру WordPress страница, постова, таксономија и виџета (ако то подржавају).','These tags have a special purpose and work separately from short codes and can be used in fields where short codes cannot be used.'=>'Ови тагови имају посебну намену и раде одвојено од кратких кодова и могу се користити у пољима у којима се кратки кодови не могу користити.','These tags have no additional settings and can be applied in plugins, themes, widgets and within other short codes.'=>'Ови тагови немају додатна подешавања и могу се применити у додацима, темама, виџетима и у оквиру других кратких кодова.','Copy the desired text into one field and press the desired key to convert the text.'=>'Копирајте жељени текст у једно поље и притисните жељени тастер да бисте га конвертовали.','Convert to Latin'=>'Конвертуј у латиницу','Convert to Cyrillic'=>'Конвертуј у ћирилицу','Reset'=>'Очисти све','The %1$s shortcode has been deprecated as of version %2$s. Please update your content and use the new %3$s shortcode.'=>'Кратки код %1$s је означен као застарели од верзије %2$s. Молимо вас да ажурирате свој садржај и користите нови шорткод %3$s.','Transliteration shortcode does not have adequate parameters and translation is not possible. Please check the documentation.'=>'Кратки код за пресловљавање нема адекватне параметре и превођење није могуће. Молимо погледајте документацију.','An error occurred while converting. Please refresh the page and try again.'=>'Дошло је до грешке приликом конверзије. Освежите страницу и покушајте поново.','The field is empty.'=>'Поље је празно.','There was a communication problem. Please refresh the page and try again. If this does not solve the problem, contact the author of the plugin.'=>'Дошло је до проблема у комуникацији. Освежите страницу и покушајте поново. Ако ово не реши проблем, обратите се аутору додатка.','Serbian'=>'Српски','Bosnian'=>'Босански','Montenegrin'=>'Црногорски','Croatian'=>'Хрватски','Russian'=>'Руски','Belarusian'=>'Белоруски','Bulgarian'=>'Бугарски','Macedoanian'=>'Македноски','Ukrainian'=>'Украјински','Kazakh'=>'Казахстански','Tajik'=>'Таџик','Kyrgyz'=>'Киргиски','Mongolian'=>'Монголски','Bashkir'=>'Башкир','Uzbek'=>'Узбек','Georgian'=>'Грузијски','Greek'=>'Грчки','Phantom Mode (ultra fast DOM-based transliteration)'=>'Фантомски режим (ултра брза транслитерација заснована на ДОМ-у)','Light mode (basic parts of the site)'=>'Лаган режим (основни делови сајта)','Standard mode (content, themes, plugins, translations, menu)'=>'Стандардни режим (садржај, теме, додаци, преводи, мени)','Advanced mode (content, widgets, themes, plugins, translations, menu, permalinks, media)'=>'Напредни режим (садржај, виџети, теме, додаци, преводи, мени, трајне везе, медији)','Forced transliteration (everything)'=>'Присилно пресловљавање (све)','Only WooCommerce (It bypasses all other transliterations and focuses only on WooCommerce)'=>'Само WooCommerce (заобилази све остале транслитерације и фокусира се само на WooCommerce)','Dev Mode (Only for developers and testers)'=>'Програмерски мод (само за програмере)',' degrees '=>' степени ',' divided by '=>' подељено са ',' times '=>' пута ',' plus-minus '=>' плус-минус ',' square root '=>' квадратни корен ',' infinity '=>' бесконачност ',' almost equal to '=>' скоро једнако са ',' not equal to '=>' није једнако са ',' identical to '=>' индентично са ',' less than or equal to '=>' мање или једнако ',' greater than or equal to '=>' веће или једнако са ',' left '=>' лево ',' right '=>' десно ',' up '=>' горе ',' down '=>' доле ',' left and right '=>' лево и десно ',' up and down '=>' горе и доле ',' care of '=>' брига о ',' estimated '=>' процењено ',' ohm '=>' ом ',' female '=>' женско ',' male '=>' мушко ',' Copyright '=>' Ауторско право ',' Registered '=>' Регистровано ',' Trademark '=>' Заштитни знак ','Option name'=>'Назив опције','Value'=>'Вредност','Key'=>'Кључ','Automatic'=>'Аутоматски','Disabled'=>'Онемогућено','Please wait! Do not close the terminal or terminate the script until this operation is completed!'=>'Сачекајте! Немојте затварати терминал или прекидати скрипту док се ова операција не заврши!','Progress:'=>'Напредак:','Updated page ID %1$d, (%2$s) at URL: %3$s'=>'Ажурирана страница "%2$s" на адреси %3$s са индентификатором (ID): %1$d','%d permalink was successfully transliterated.'=>'Успешно је ажурирана %d страница.' . "\0" . 'Успешно је ажурирано %d страница.' . "\0" . 'Успешно је ажурирано %d страница.','No changes to the permalink have been made.'=>'Није промењена ниједна трајна веза.','This function is deprecated and will be removed. Replace it with the `get_script()` function'=>'Ова функција је застарела и биће уклоњена. Замените је са get_script() функцијом','Choose one of the display types: "%1$s", "%2$s", "%3$s", "%4$s", "%5$s" or "%6$s"'=>'Одаберите једно од приказа: "%1$s", "%2$s", "%3$s", "%4$s", "%5$s" или "%6$s"','Transliterator'=>'Пресловљавање','You do not have sufficient permissions to access this page.'=>'Немате довољна овлашћења да приступите овој страници.','Security check failed. Please try again.'=>'Безбедносна провера није успела. Покушајте поново.','Transliterator - Network Settings'=>'Транслитерација - Мрежна подешавања','Select sites where the plugin should run when it is network-activated.'=>'Изаберите сајтове на којима ће се додатак покретати када је мрежно активиран.','Enable'=>'Одобри','Site'=>'Сајт','Domain'=>'Домен','Path'=>'Путања','Site #%d'=>'Сајт #%d','Enable Transliterator on site ID %d'=>'Омогући Transliterator на ID сајта %d','No sites found.'=>'Није пронађен ниједан сајт.','Save changes'=>'Сачувај промене','Transliterator – Multilingual and Multi-script Text Conversion'=>'Транслитератор – Вишејезичка и вишеписмена конверзија текста','https://wordpress.org/plugins/serbian-transliteration/'=>'https://wordpress.org/plugins/serbian-transliteration/','All-in-one Cyrillic to Latin transliteration plugin for WordPress. Supports Slavic, Arabic, Greek, and Central Asian scripts.'=>'Свеобухватан додатак за трансформацију текста са ћирилице на латиницу за ВордПрес. Подржава словенска, арапска, грчка и средњоазијска писма.','Ivijan-Stefan Stipić'=>'Ивијан-Стефан Стипић','https://profiles.wordpress.org/ivijanstefan/'=>'https://profiles.wordpress.org/ivijanstefan/']];
